import{_ as e,a as d,o as l,P as n}from"./chunks/framework.C4T-_spZ.js";const y=JSON.parse('{"title":"Glob 模式匹配","description":"Glob 模式匹配","frontmatter":{"id":1735871217623,"date":"2025/01/03 15:11","title":"Glob 模式匹配","description":"Glob 模式匹配","tag":"随笔","archive":null,"recommendations":null,"hidden":false,"top":0},"headers":[],"relativePath":"GlobPatternMatching.md","filePath":"GlobPatternMatching.md"}'),r={name:"GlobPatternMatching.md"};function a(c,t,s,i,o,g){return l(),d("div",null,t[0]||(t[0]=[n('<h1 id="glob-模式匹配" tabindex="-1">Glob 模式匹配 <a class="header-anchor" href="#glob-模式匹配" aria-label="Permalink to &quot;Glob 模式匹配&quot;">​</a></h1><p>Glob 模式匹配是一种文件名匹配规则，它允许你使用特定的模式来匹配文件系统中的文件名。这种模式匹配通常用于命令行界面和编程语言中，以便于用户和开发者能够快速地选择一组文件，而不是逐一指定每个文件。</p><p>Glob 模式匹配在不同的操作系统和编程语言中可能有一些差异，但基本的通配符和概念是相似的。在 Unix-like 系统中，Glob 是一个常用的命令行工具，而在编程语言如 Python 中，也有内置的库（如 Glob 模块）来实现类似的功能。</p><blockquote><p>在线匹配校验工具 <a href="https://globster.xyz/" target="_blank" rel="noreferrer">Glob tester</a></p></blockquote><h2 id="语法" tabindex="-1">语法 <a class="header-anchor" href="#语法" aria-label="Permalink to &quot;语法&quot;">​</a></h2><p>对于一个路径如 <code>/project/assets/logo.png</code>，其中 <code>/</code> 表示分隔符，<code>.png</code> 表示文件后缀名。</p><p>Glob 匹配语法与正则表达式类似。具有通配符，匹配数量，或运算，非运算等。</p><blockquote><blockquote><p>分隔符无法通过通配符匹配（**表示全部子孙级目录文件）。</p></blockquote></blockquote><table tabindex="0"><thead><tr><th>通配符</th><th>解释</th></tr></thead><tbody><tr><td>*</td><td>匹配单个片段中零或多个字符</td></tr><tr><td>**</td><td>匹配多个/跨片段中的零或多个字符</td></tr><tr><td>?</td><td>匹配路径中的一个字符</td></tr><tr><td>[abc]</td><td>匹配方括号中任意一个字符</td></tr><tr><td>[a-e]</td><td>匹配字符范围中任意一个字符</td></tr><tr><td>[^abc]</td><td>匹配字符范围外任意一个字符</td></tr><tr><td>{a,bc,d}</td><td>匹配全部字符（a 或者 bc 或者 d，可以同时匹配多个）</td></tr><tr><td>{a..d}</td><td>匹配范围全部字符（a 或者 b 或者 c 或者 d）</td></tr><tr><td>!(pattern | pattern | pattern)</td><td>匹配给定的匹配规则外的结果</td></tr><tr><td>?(pattern | pattern | pattern)</td><td>匹配给定的匹配规则中 0 次或 1 次的结果</td></tr><tr><td>+(pattern | pattern | pattern)</td><td>匹配给定的匹配规则中大于 1 次的结果</td></tr><tr><td>*(pattern | pattern | pattern)</td><td>匹配给定的匹配规则中任意次的结果</td></tr><tr><td>@(pattern | pattern | pattern)</td><td>匹配给定的匹配规则中 1 次的结果</td></tr></tbody></table><h2 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">匹配</th><th style="text-align:center;">/a.js</th><th style="text-align:center;">/b.png</th><th style="text-align:center;">/c.js</th><th style="text-align:center;">/d.js</th><th style="text-align:center;">/e/s1.js</th><th style="text-align:center;">/e/s2.js</th><th style="text-align:center;">/e/s3.png</th><th style="text-align:center;">f/a.js</th><th style="text-align:center;">f/a.png</th></tr></thead><tbody><tr><td style="text-align:center;">/*.js</td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">/e/*.js</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">/e/s?.png</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">/?/?.png</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td></tr><tr><td style="text-align:center;">/[abc].js</td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">/?/s[1-9].js</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">/**/?[^2].*</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">/*.{png,js}</td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">/{e,f}/{s,a}.*</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td></tr><tr><td style="text-align:center;">/**/!(?.js)</td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td></tr><tr><td style="text-align:center;">/e/s?(1|2).js</td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"><code>√</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr></tbody></table><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ol><li><a href="https://globster.xyz/" target="_blank" rel="noreferrer">Glob tester - tool for testing glob patterns</a></li><li><a href="https://knife.blog.csdn.net/article/details/125043362" target="_blank" rel="noreferrer">glob 匹配规则--使用/教程/实例_glob 规则-CSDN 博客</a></li></ol>',13)]))}const h=e(r,[["render",a]]);export{y as __pageData,h as default};
